{
	"$schema": "https://schemas.wp.org/trunk/theme.json",
	"version": 3,
	"settings": {
		"appearanceTools": true,
		"layout": {
			"contentSize": "860px",
			"wideSize": "1280px"
		},
		"color": {
			"palette": [
				{
					"slug": "parchment",
					"color": "#F5F0E8",
					"name": "Parchment"
				},
				{
					"slug": "ink",
					"color": "#1C1C1C",
					"name": "Ink"
				},
				{
					"slug": "saffron",
					"color": "#C0622F",
					"name": "Saffron"
				},
				{
					"slug": "sage",
					"color": "#7A9E7E",
					"name": "Sage"
				},
				{
					"slug": "warm-gray",
					"color": "#A89F91",
					"name": "Warm Gray"
				},
				{
					"slug": "cream",
					"color": "#FAF7F2",
					"name": "Cream"
				},
				{
					"slug": "deep-teal",
					"color": "#2C4A4E",
					"name": "Deep Teal"
				}
			],
			"gradients": [
				{
					"slug": "parchment-to-cream",
					"gradient": "linear-gradient(180deg, #F5F0E8 0%, #FAF7F2 100%)",
					"name": "Parchment to Cream"
				},
				{
					"slug": "saffron-fade",
					"gradient": "linear-gradient(135deg, #C0622F 0%, #D4915A 100%)",
					"name": "Saffron Fade"
				}
			]
		},
		"typography": {
			"fontFamilies": [
				{
					"fontFamily": "'Playfair Display', Georgia, 'Times New Roman', serif",
					"slug": "playfair",
					"name": "Playfair Display"
				},
				{
					"fontFamily": "'Space Mono', 'Courier New', monospace",
					"slug": "space-mono",
					"name": "Space Mono"
				}
			],
			"fontSizes": [
				{
					"slug": "small",
					"size": "0.875rem",
					"name": "Small"
				},
				{
					"slug": "medium",
					"size": "1rem",
					"name": "Medium"
				},
				{
					"slug": "large",
					"size": "1.25rem",
					"name": "Large"
				},
				{
					"slug": "x-large",
					"size": "1.75rem",
					"name": "Extra Large"
				},
				{
					"slug": "xx-large",
					"size": "2.25rem",
					"name": "Double Extra Large"
				},
				{
					"slug": "display",
					"size": "clamp(2.5rem, 5vw, 3.5rem)",
					"name": "Display"
				}
			]
		},
		"spacing": {
			"units": ["px", "em", "rem", "vh", "vw", "%"],
			"spacingSizes": [
				{ "slug": "10", "size": "0.5rem", "name": "1" },
				{ "slug": "20", "size": "1rem", "name": "2" },
				{ "slug": "30", "size": "1.5rem", "name": "3" },
				{ "slug": "40", "size": "2rem", "name": "4" },
				{ "slug": "50", "size": "3rem", "name": "5" },
				{ "slug": "60", "size": "4rem", "name": "6" },
				{ "slug": "70", "size": "5rem", "name": "7" },
				{ "slug": "80", "size": "7rem", "name": "8" }
			]
		}
	},
	"styles": {
		"color": {
			"background": "#F5F0E8",
			"text": "#1C1C1C"
		},
		"typography": {
			"fontFamily": "'Space Mono', 'Courier New', monospace",
			"fontSize": "1rem",
			"lineHeight": "1.65"
		},
		"spacing": {
			"blockGap": "1.5rem"
		},
		"elements": {
			"heading": {
				"typography": {
					"fontFamily": "'Playfair Display', Georgia, 'Times New Roman', serif",
					"fontWeight": "900",
					"lineHeight": "1.15"
				},
				"color": {
					"text": "#1C1C1C"
				}
			},
			"h1": {
				"typography": {
					"fontSize": "clamp(2.5rem, 5vw, 3.5rem)",
					"letterSpacing": "-1px"
				}
			},
			"h2": {
				"typography": {
					"fontSize": "2.25rem",
					"letterSpacing": "-0.5px"
				}
			},
			"h3": {
				"typography": {
					"fontSize": "1.75rem"
				}
			},
			"h4": {
				"typography": {
					"fontSize": "1.25rem"
				}
			},
			"link": {
				"color": {
					"text": "#C0622F"
				},
				":hover": {
					"color": {
						"text": "#7A9E7E"
					}
				}
			},
			"button": {
				"color": {
					"background": "#1C1C1C",
					"text": "#F5F0E8"
				},
				"typography": {
					"fontFamily": "'Space Mono', 'Courier New', monospace",
					"fontSize": "0.875rem",
					"fontWeight": "700",
					"letterSpacing": "1px",
					"textTransform": "uppercase"
				},
				"border": {
					"radius": "0px"
				},
				":hover": {
					"color": {
						"background": "#C0622F",
						"text": "#F5F0E8"
					}
				}
			}
		},
		"blocks": {
			"core/navigation": {
				"typography": {
					"fontFamily": "'Space Mono', 'Courier New', monospace",
					"fontSize": "0.85rem",
					"fontWeight": "700",
					"textTransform": "uppercase",
					"letterSpacing": "1px"
				}
			},
			"core/site-title": {
				"typography": {
					"fontFamily": "'Playfair Display', Georgia, 'Times New Roman', serif",
					"fontSize": "1.5rem",
					"fontWeight": "900",
					"letterSpacing": "-0.5px"
				},
				"elements": {
					"link": {
						"color": {
							"text": "#1C1C1C"
						},
						":hover": {
							"color": {
								"text": "#C0622F"
							}
						},
						"typography": {
							"textDecoration": "none"
						}
					}
				}
			},
			"core/post-title": {
				"elements": {
					"link": {
						"color": {
							"text": "#1C1C1C"
						},
						":hover": {
							"color": {
								"text": "#C0622F"
							}
						},
						"typography": {
							"textDecoration": "none"
						}
					}
				}
			},
			"core/quote": {
				"border": {
					"left": {
						"color": "#C0622F",
						"width": "4px",
						"style": "solid"
					}
				},
				"typography": {
					"fontFamily": "'Playfair Display', Georgia, 'Times New Roman', serif",
					"fontStyle": "italic"
				}
			},
			"core/separator": {
				"color": {
					"text": "#1C1C1C"
				},
				"border": {
					"width": "3px"
				}
			},
			"core/code": {
				"color": {
					"background": "#FAF7F2",
					"text": "#1C1C1C"
				},
				"border": {
					"color": "#1C1C1C",
					"width": "2px",
					"style": "solid"
				}
			}
		}
	},
	"templateParts": [
		{
			"name": "header",
			"title": "Header",
			"area": "header"
		},
		{
			"name": "footer",
			"title": "Footer",
			"area": "footer"
		}
	]
}

/*
Theme Name: Bombay Pirate Retro Revival
Author: WordPress Telex
Description: A retro-contemporary editorial block theme inspired by vintage Indian broadsheet newspapers, featuring warm parchment tones, saffron and sage accents, Playfair Display headlines paired with Space Mono body text, and a charming elephant trail motif. Built for the Bombay Pirate blog by Aditya Kane.
Version: 0.1.0
Requires at least: 6.4
Tested up to: 6.8
Requires PHP: 7.4
License: GPLv2 or later
Text Domain: telex-bombay-pirate-retro
Tags: block-theme, full-site-editing, blog, editorial

Bombay Pirate Retro Revival — calm, quirky, joyful.
*/

/* ── Base resets ── */
.wp-site-blocks > * + * {
	margin-block-start: 0;
}

.wp-site-blocks > footer {
	margin-block-start: 0;
}

/* ── Header ── */
.broadsheet-header {
	border-bottom: 4px solid var(--wp--preset--color--ink);
}

.broadsheet-header .wp-block-navigation a {
	transition: color 0.3s ease;
}

.broadsheet-header .wp-block-navigation a:hover {
	color: var(--wp--preset--color--sage) !important;
}

/* ── Ornament dividers ── */
.ornament-rule {
	display: flex;
	align-items: center;
	gap: 1rem;
	padding: 0.75rem 0;
}

.ornament-rule::before,
.ornament-rule::after {
	content: "";
	flex: 1;
	height: 3px;
	background-color: var(--wp--preset--color--ink);
}

.ornament-rule .wp-block-separator {
	display: none;
}

/* ── Star divider ── */
.star-divider {
	text-align: center;
	font-size: 1.25rem;
	letter-spacing: 1.5rem;
	color: var(--wp--preset--color--ink);
}

/* ── Hero image frame ── */
.broadsheet-frame {
	padding: 0.75rem;
	border: 4px solid var(--wp--preset--color--ink);
	box-shadow: 12px 12px 0px rgba(28, 28, 28, 0.1);
	transform: rotate(0.75deg);
	transition: transform 0.4s ease;
	position: relative;
}

.broadsheet-frame:hover {
	transform: rotate(0deg);
}

.broadsheet-frame img {
	filter: sepia(0.15) contrast(1.05);
	border: 2px solid var(--wp--preset--color--ink);
}

/* ── Tag pill style ── */
.broadsheet-tag {
	display: inline-block;
	font-size: 0.75rem;
	text-transform: uppercase;
	padding: 0.25rem 0.75rem;
	border: 2px solid var(--wp--preset--color--sage);
	color: var(--wp--preset--color--sage);
	font-weight: 700;
	letter-spacing: 1px;
	font-family: 'Space Mono', 'Courier New', monospace;
}

/* ── Section ink borders ── */
.ink-border-top {
	border-top: 3px solid var(--wp--preset--color--ink);
}

.ink-border-bottom {
	border-bottom: 3px solid var(--wp--preset--color--ink);
}

.ink-border-double-top {
	border-top: 6px double var(--wp--preset--color--ink);
}

/* ── Elephant track ── */
.elephant-track {
	display: flex;
	align-items: center;
	gap: 0.5rem;
	padding: 1rem 0;
}

.elephant-track::before {
	content: "";
	flex: 1;
	height: 10px;
	background-image: radial-gradient(circle, var(--wp--preset--color--saffron) 2.5px, transparent 3px);
	background-size: 16px 16px;
	background-repeat: repeat-x;
	background-position: center;
	opacity: 0.7;
}

/* ── Card styles ── */
.equal-cards > .wp-block-column {
	display: flex;
	flex-direction: column;
	flex-grow: 0;
}

.equal-cards > .wp-block-column > .wp-block-group {
	display: flex;
	flex-direction: column;
	flex-grow: 1;
}

.equal-cards .cta-bottom {
	margin-top: auto;
	justify-content: center;
}

/* ── Post cards ── */
.post-card {
	border: 3px solid var(--wp--preset--color--ink);
	padding: 1.5rem;
	transition: box-shadow 0.3s ease, transform 0.3s ease;
	background: var(--wp--preset--color--cream);
}

.post-card:hover {
	box-shadow: 8px 8px 0px rgba(28, 28, 28, 0.12);
	transform: translateY(-2px);
}

/* ── Category labels ── */
.category-label {
	font-family: 'Space Mono', 'Courier New', monospace;
	font-size: 0.75rem;
	text-transform: uppercase;
	letter-spacing: 1.5px;
	font-weight: 700;
}

/* ── Photo gallery grid ── */
.photo-grid figure {
	border: 3px solid var(--wp--preset--color--ink);
	padding: 0.4rem;
	background: var(--wp--preset--color--cream);
	transition: transform 0.3s ease, box-shadow 0.3s ease;
}

.photo-grid figure:hover {
	transform: rotate(-1deg);
	box-shadow: 6px 6px 0 rgba(28, 28, 28, 0.1);
}

.photo-grid img {
	filter: sepia(0.1) contrast(1.05);
}

/* ── Grain overlay utility ── */
.grain-overlay {
	position: relative;
}

.grain-overlay::after {
	content: "";
	position: absolute;
	inset: 0;
	background-image: url('data:image/svg+xml;utf8,<svg viewBox="0 0 256 256" xmlns="http://www.w3.org/2000/svg"><filter id="noise"><feTurbulence type="fractalNoise" baseFrequency="0.85" numOctaves="4" stitchTiles="stitch"/></filter><rect width="100%" height="100%" filter="url(%23noise)" opacity="0.08"/></svg>');
	mix-blend-mode: multiply;
	pointer-events: none;
	z-index: 1;
}

/* ── Letterpress text effect ── */
.letterpress {
	text-shadow:
		2px 2px 0px rgba(28, 28, 28, 0.12),
		-1px -1px 0px rgba(255, 255, 255, 0.5);
}

/* ── Saffron accent underline ── */
.saffron-underline {
	text-decoration: underline;
	text-decoration-color: var(--wp--preset--color--saffron);
	text-underline-offset: 4px;
	text-decoration-thickness: 3px;
}

/* ── Scroll animations ── */
@keyframes fadeInUp {
	from {
		opacity: 0;
		transform: translateY(24px);
	}
	to {
		opacity: 1;
		transform: translateY(0);
	}
}

.animate-on-scroll {
	animation: fadeInUp 0.6s ease-out both;
}

/* ── Footer ── */
.broadsheet-footer {
	border-top: 6px double var(--wp--preset--color--ink);
}

.broadsheet-footer a {
	transition: color 0.3s ease;
}

/* ── Scroll Elephant ── */
.scroll-elephant-container {
	position: fixed;
	bottom: 1.5rem;
	left: 0;
	width: 100%;
	height: 56px;
	pointer-events: none;
	z-index: 9999;
	overflow: hidden;
}

.scroll-elephant {
	position: absolute;
	bottom: 0;
	left: -60px;
	width: 56px;
	height: 56px;
	transition: none;
	will-change: transform;
}

.scroll-elephant svg {
	width: 56px;
	height: 56px;
	display: block;
}

.scroll-elephant-trail {
	position: absolute;
	bottom: 6px;
	left: 0;
	height: 10px;
	width: 0;
	background-image: radial-gradient(circle, var(--wp--preset--color--saffron, #C0622F) 2px, transparent 2.5px);
	background-size: 14px 14px;
	background-repeat: repeat-x;
	background-position: left center;
	opacity: 0.55;
	transition: none;
	will-change: width;
}

/* Bob animation for the elephant */
@keyframes elephantBob {
	0%, 100% { transform: translateY(0); }
	50% { transform: translateY(-3px); }
}

.scroll-elephant--walking svg {
	animation: elephantBob 0.4s ease-in-out infinite;
}

/* Hide on very small screens where it crowds the UI */
@media (max-width: 480px) {
	.scroll-elephant-container {
		display: none;
	}
}

/* ── Responsive ── */
@media (max-width: 768px) {
	.broadsheet-frame {
		transform: rotate(0deg);
		box-shadow: 6px 6px 0px rgba(28, 28, 28, 0.08);
	}
}

/**
 * Scroll Elephant — the little saffron elephant that walks
 * from left to right as the visitor scrolls down the page.
 */
document.addEventListener( 'DOMContentLoaded', function () {
	var container = document.querySelector( '.scroll-elephant-container' );
	var elephant = document.querySelector( '.scroll-elephant' );
	var trail = document.querySelector( '.scroll-elephant-trail' );

	if ( ! container || ! elephant || ! trail ) {
		return;
	}

	var elephantWidth = 56;
	var lastScrollY = -1;
	var ticking = false;
	var walkingTimeout = null;

	function getScrollProgress() {
		var scrollTop = window.pageYOffset || document.documentElement.scrollTop;
		var docHeight = Math.max(
			document.body.scrollHeight,
			document.documentElement.scrollHeight
		);
		var winHeight = window.innerHeight;
		var scrollable = docHeight - winHeight;

		if ( scrollable <= 0 ) {
			return 0;
		}

		return Math.min( Math.max( scrollTop / scrollable, 0 ), 1 );
	}

	function update() {
		ticking = false;

		var progress = getScrollProgress();
		var viewportWidth = window.innerWidth;
		var maxTravel = viewportWidth + elephantWidth;
		var xPos = -elephantWidth + ( progress * maxTravel );

		elephant.style.left = xPos + 'px';

		var trailWidth = Math.max( 0, xPos );
		trail.style.width = trailWidth + 'px';
	}

	function onScroll() {
		var currentY = window.pageYOffset || document.documentElement.scrollTop;

		// Add walking class for the bob animation
		elephant.classList.add( 'scroll-elephant--walking' );

		// Clear previous timeout and set a new one to stop bobbing
		if ( walkingTimeout ) {
			clearTimeout( walkingTimeout );
		}
		walkingTimeout = setTimeout( function () {
			elephant.classList.remove( 'scroll-elephant--walking' );
		}, 200 );

		if ( currentY !== lastScrollY ) {
			lastScrollY = currentY;

			if ( ! ticking ) {
				ticking = true;
				requestAnimationFrame( update );
			}
		}
	}

	// Set the saffron color
	elephant.style.color = getComputedStyle( document.documentElement )
		.getPropertyValue( '--wp--preset--color--saffron' )
		.trim() || '#C0622F';

	// Initial position
	update();

	window.addEventListener( 'scroll', onScroll, { passive: true } );
	window.addEventListener( 'resize', function () {
		if ( ! ticking ) {
			ticking = true;
			requestAnimationFrame( update );
		}
	}, { passive: true } );
} );

/**
 * Theme Assets Editor Rewrite
 *
 * This script rewrites URLs in block attributes that start with 'theme:./'
 * to point to the correct theme assets.
 * It allows blocks in templates to reference theme assets using relative paths in the editor.
**/
(function (wp) {
	const base = window.THEME_ASSETS_BASE_URL || '';
	const prefix = 'theme:./';

	if (!wp?.hooks || !wp?.compose) return;

	const rewrite = (url) => {
		if (typeof url === 'string' && url.startsWith(prefix)) {
			const path = url.slice(prefix.length);
			return base + '/' + path;
		}
		return null;
	};

	// Recursively walk any value and rewrite all theme:./ URLs found in it.
	// Returns a new structure if anything changed, or null if nothing changed.
	const deepRewrite = (value) => {
		if (typeof value === 'string') {
			return rewrite(value);
		}
		if (Array.isArray(value)) {
			let changed = false;
			const result = value.map((item) => {
				const rewritten = deepRewrite(item);
				if (rewritten !== null) {
					changed = true;
					return rewritten;
				}
				return item;
			});
			return changed ? result : null;
		}
		if (value && typeof value === 'object') {
			let changed = false;
			const result = {};
			for (const key of Object.keys(value)) {
				const rewritten = deepRewrite(value[key]);
				if (rewritten !== null) {
					changed = true;
					result[key] = rewritten;
				} else {
					result[key] = value[key];
				}
			}
			return changed ? result : null;
		}
		return null;
	};

	wp.hooks.addFilter(
		'editor.BlockEdit',
		'theme-assets/rewrite-image-urls',
		wp.compose.createHigherOrderComponent((BlockEdit) => (props) => {
			const { attributes } = props;

			// Deep-rewrite all attributes to resolve any theme:./ URLs
			const rewrittenAttributes = deepRewrite(attributes);

			// Pass rewritten URLs to BlockEdit for display only, without persisting changes
			if (rewrittenAttributes) {
				const modifiedProps = {
					...props,
					attributes: rewrittenAttributes,
				};
				return wp.element.createElement(BlockEdit, modifiedProps);
			}

			return wp.element.createElement(BlockEdit, props);
		}, 'withThemeAssetsRewrite')
	);

})(window.wp);
